const staticData = $getWorkflowStaticData('node');

const attempts = staticData.attempts ?? 0;
const newAttempts = attempts + 1;

if (newAttempts >= 3) {
    staticData.attempts = 0; // reset for next execution
    return [{ json: { ...$json, attempts: newAttempts, is_failed: 'yes' } }];
}

staticData.attempts = newAttempts;
return [{ json: { ...$json, attempts: newAttempts, is_failed: 'no' } }];

const output = $json.output || '';

const requiredKeywords = [
    ['Revenue', 'Projections de revenus', 'Revenus'],
    ['Cost', 'Structure des coûts', 'Coûts'],
    ['Funding', 'Financement'],
    ['Break', 'Seuil de rentabilité'],
];

const missingKeywords = requiredKeywords.filter(group =>
    !group.some(kw => output.toLowerCase().includes(kw.toLowerCase()))
);

return [{
    json: {
        ...$json,
        keywords_valid: missingKeywords.length === 0 ? 'true' : 'false',
        missing_keywords: missingKeywords.map(g => g[0]),
    }
}];

const output = $json.output || '';
const minLength = 400;
const length_valid = output.length >= minLength ? 'true' : 'false';

return [{
  json: {
    ...$json,
    length_valid: length_valid,
    actual_length: output.length,
  }
}];

const body = $json.body || $json;
const input = body.input_json || {};
const context = body.plan_context || {};
const language = body.language || 'english';
const businessPlanId = body.business_plan_id;
const sectionId = body.section_id;

const headings = language === 'french' ? `
- Projections de revenus
- Structure des coûts
- Besoins en financement
- Analyse du seuil de rentabilité
` : `
- Revenue Projections
- Cost Structure
- Funding Requirements
- Break-even Analysis
`;

const prompt = `
You are a professional financial advisor writing the Financial Plan section of a business plan.
Language: ${language}

## Company Context
${context.company_presentation || 'Not provided'}

## Strategy Context
${context.strategy || 'Not provided'}

## Operational Context
${context.operational_plan || 'Not provided'}

## User Provided Financial Data
- Startup Costs: ${input.startup_costs || 'Not provided'}
- Monthly Burn Rate: ${input.monthly_burn || 'Not provided'}
- Break-even Point: ${input.breakeven || 'Not provided'}
- Revenue Year 1: ${input.revenue_y1 || 'Not provided'}
- Revenue Year 2: ${input.revenue_y2 || 'Not provided'}
- Revenue Year 3: ${input.revenue_y3 || 'Not provided'}
- Funding Sources: ${input.funding_sources || 'Not provided'}
- Financial Assumptions: ${input.financial_assumptions || 'Not provided'}

## Your Task

You must produce TWO things in your response:

### PART 1 — NARRATIVE TEXT
Write a detailed Financial Plan section with these headings: ${headings}

Use the user's data as a base but enhance it with realistic projections.
Base your projections on the company's industry, location, and business model described in the Company Context above.
Make projections ambitious but achievable given the specific market, domain, and region of this business.
Minimum 400 words. Write in ${language}.

### PART 2 — STRUCTURED DATA
After the narrative, add this exact block with realistic numbers derived from the narrative:

---CHART_DATA_START---
{
  "revenue": [YEAR1_NUMBER, YEAR2_NUMBER, YEAR3_NUMBER],
  "costs": [YEAR1_COSTS, YEAR2_COSTS, YEAR3_COSTS],
  "profit": [YEAR1_PROFIT, YEAR2_PROFIT, YEAR3_PROFIT],
  "breakeven_month": MONTH_NUMBER,
  "arpu": MONTHLY_REVENUE_PER_USER,
  "monthly_growth_rate": PERCENTAGE,
  "cost_breakdown_y1": {
    "development": NUMBER,
    "marketing": NUMBER,
    "operations": NUMBER
  },
  "cost_breakdown_y2": {
    "development": NUMBER,
    "marketing": NUMBER,
    "operations": NUMBER
  },
  "cost_breakdown_y3": {
    "development": NUMBER,
    "marketing": NUMBER,
    "operations": NUMBER
  }
}
---CHART_DATA_END---
---MEMORY_SUMMARY---
Startup Costs: [value]
Monthly Burn: [value]
Breakeven: [value]
Revenue Y1: [value]
Revenue Y2: [value]
Revenue Y3: [value]
Funding: [value]
Cost Structure: [value]

Rules:
- Numbers must be realistic and consistent with the narrative
- All numbers must be plain integers or decimals, no currency symbols
- The profit array = revenue minus costs for each year
- Base all projections on the company industry, domain and region from the context above
`;

return [{
    json: {
        prompt,
        section_id: sectionId,
        business_plan_id: businessPlanId,
        section_name: 'financial_plan',
        language,
        input_json: input,
    }
}];

const raw = $('AI Agent').item.json.output || '';

// Extract chart data
const chartDataMatch = raw.match(/---CHART_DATA_START---([\s\S]*?)---CHART_DATA_END---/);

let chartData = null;
let narrativeText = raw;

if (chartDataMatch) {
    try {
        // Fix French number formatting (20 000 → 20000) and math expressions
        const rawJson = chartDataMatch[1].trim()
            .replace(/(\d)\s+(\d)/g, '$1$2')
            .replace(/(\d+(?:\+\d+)+)/g, (match) => eval(match));
        chartData = JSON.parse(rawJson);
        narrativeText = raw
            .replace(/---CHART_DATA_START---[\s\S]*?---CHART_DATA_END---/, '')
            .replace(/###\s*PART\s*[12]\s*[—-]\s*[\w\s]+/gi, '')
            .trim();
    } catch (e) {
        chartData = null;
        console.log('chart parse error:', e.message);
    }
}

// Match MEMORY_SUMMARY with any delimiter or even no delimiter
let memMatch = narrativeText.match(/(?:===|---|\*\*|)\s*MEMORY_SUMMARY\s*(?:===|---|\*\*|)[^\n]*\n([\s\S]*?)$/i);
const memory_summary = memMatch ? memMatch[1].trim() : '';

// Remove everything from MEMORY_SUMMARY onwards
let cleanNarrative = narrativeText.replace(/(?:===|---|\*\*|)\s*MEMORY_SUMMARY\s*[\s\S]*$/i, '').trim();

// Strip any stray === headings === from narrative
cleanNarrative = cleanNarrative.replace(/===\s*[^=]*?\s*===/g, '').trim();

// Strip any stray === headings === from narrative
cleanNarrative = cleanNarrative.replace(/===\s*[^=]*?\s*===/g, '').trim();

// Token estimation
const promptText    = $('Build Prompt').item.json.prompt || '';
const tokens_input  = Math.round(promptText.length / 4);
const tokens_output = Math.round(raw.length / 4);
const tokens_total  = tokens_input + tokens_output;

const buildData = $('Build Prompt').item.json;
return [{
    json: {
        ...buildData,
        output: cleanNarrative,
        chart_data: chartData ? JSON.stringify(chartData) : null,
        memory_summary,
        tokens_input,
        tokens_output,
        tokens_total,
    }
}];
